parameters.jsCode:
const rows = $input.all();
const total = rows.length;
const newLeads = rows.filter(r => r.json.Status === 'New Lead').length;
const contacted = rows.filter(r => r.json.Status === 'Contacted').length;
const errors = rows.filter(r => r.json.Error !== '').length;

return [{
  json: {
    total,
    newLeads,
    contacted,
    errors
  }
}];

