let assigned_rep = 'Unknown';

try {
  assigned_rep = $('Assign Junior Rep').first().json.assigned_rep;
} catch(e) {
  try {
    assigned_rep = $('Assign Senior Rep').first().json.assigned_rep;
  } catch(e) {
    assigned_rep = 'Unknown';
  }
}

return [{
  json: {
    assigned_rep: assigned_rep,
    url: $('Create Trello Task').first().json.url
  }
}];

