const fromField = $json.From || '';
const emailMatch = fromField.match(/<(.+?)>/) || fromField.match(/([^\s]+@[^\s]+)/);
const email = emailMatch ? emailMatch[1] || emailMatch[0] : '';

return { json: { ...($json), extractedEmail: email.trim() } };
